import{_ as s,e as o}from"./app.659fa32e.js";const r={},t=o('<h4 id="js\u7684\u5783\u573E\u56DE\u6536\u673A\u5236" tabindex="-1"><a class="header-anchor" href="#js\u7684\u5783\u573E\u56DE\u6536\u673A\u5236" aria-hidden="true">#</a> JS\u7684\u5783\u573E\u56DE\u6536\u673A\u5236</h4><p>\u200B JS\u7684\u5783\u573E\u56DE\u6536\u673A\u5236\u90FD\u662F\u7531js\u5F15\u64CE\u5B9E\u73B0\u7684\uFF0C\u5927\u90E8\u5206\u6D4F\u89C8\u5668\u90FD\u6709\u81EA\u5DF1\u7684js\u5F15\u64CE\uFF0C\u6240\u4EE5\u5404\u81EA\u5B9E\u73B0\u7684\u5783\u573E\u56DE\u6536\u673A\u5236\u90FD\u7565\u6709\u4E0D\u540C\u3002\u4F46\u662F\u4E3B\u8981\u7684\u7B56\u7565\u5C31\u4E24\u79CD:</p><p>1\u3001<strong>\u6807\u8BB0\u6E05\u9664</strong> \u6807\u8BB0\u9636\u6BB5\uFF1A\u628A\u6240\u6709\u6D3B\u52A8\u5BF9\u8C61\u505A\u4E0A\u6807\u8BB0\u3002 \u6E05\u9664\u9636\u6BB5\uFF1A\u628A\u6CA1\u6709\u6807\u8BB0\u7684\u5BF9\u8C61\u9500\u6BC1\u3002</p><p>\u200B \u7F3A\u70B9\uFF1A\u6CA1\u6709\u88AB\u6E05\u9664\u7684\u5BF9\u8C61\u4F4D\u7F6E\u4E0D\u53D8\uFF0C\u5BFC\u81F4\u6E05\u695A\u540E\u7684\u7A7A\u95F2\u5185\u5B58\u7A7A\u95F4\u4E0D\u8FDE\u7EED\uFF08\u5185\u5B58\u788E\u7247\uFF09</p><p>2\u3001<strong>\u5F15\u7528\u8BA1\u6570</strong></p><p>\u200B \u4E00\u4E2A\u503C\u8D4B\u7ED9\u4E86\u4E00\u4E2A\u53D8\u91CF\uFF0C\u8FD9\u4E2A\u503C\u5F15\u7528\u8BA1\u6570\u52A0\u4E00\uFF0C\u53C8\u88AB\u8D4B\u7ED9\u53E6\u4E00\u4E2A\u53D8\u91CF\u5C31\u518D\u52A0\u4E00\uFF08\u7C7B\u63A8\uFF09\uFF0C\u53E6\u4E00\u4E2A\u503C\u8981\u662F\u8986\u76D6\u4E86\u539F\u672C\u5DF2\u7ECF\u8D4B\u503C\u7684\u53D8\u91CF\uFF0C\u5219\u8FD9\u4E2A\u503C\u5F15\u7528\u8BA1\u6570\u51CF\u4E00\u3002</p><p>\u200B \u7F3A\u70B9\uFF1A1\u3001\u9700\u8981\u4E00\u4E2A\u4E0D\u77E5\u4E0A\u9650\u7684\u8BA1\u6570\u5668\u30022\u3001\u5FAA\u73AF\u5F15\u7528\u65E0\u6CD5\u56DE\u6536</p><h4 id="v8\u7684\u5783\u573E\u56DE\u6536\u673A\u5236" tabindex="-1"><a class="header-anchor" href="#v8\u7684\u5783\u573E\u56DE\u6536\u673A\u5236" aria-hidden="true">#</a> v8\u7684\u5783\u573E\u56DE\u6536\u673A\u5236</h4><p>\u200B \u5206\u4EE3\u5F0F\u5783\u573E\u56DE\u6536\uFF1A\u5206\u4E3A<strong>\u65B0\u751F\u4EE3\u533A\u57DF</strong>\u548C<strong>\u8001\u751F\u4EE3\u533A\u57DF</strong>\u3002\u65B0\u751F\u4EE3\u533A\u57DF\u5BB9\u91CF\u5C0F\uFF0C\u4F1A\u4FDD\u5B58\u5B58\u6D3B\u8F83\u77ED\u3001\u4F53\u79EF\u8F83\u5C0F\u7684\u5BF9\u8C61\u3002\u8001\u751F\u4EE3\u53CD\u4E4B\u3002\u4E0D\u540C\u5206\u533A\u7684\u5783\u573E\u56DE\u6536\u673A\u5236\u4E0E\u56DE\u6536\u9891\u7387\u90FD\u4E0D\u540C\u3002</p><p><strong>\u65B0\u751F\u4EE3\u533A</strong></p><p>\u200B \u65B0\u751F\u4EE3\u533A\u53C8\u5206\u4E3A<strong>\u4F7F\u7528\u533A</strong>\u548C<strong>\u7A7A\u95F2\u533A</strong>\uFF0C\u901A\u8FC7 <code>Scavenge</code> \u7B97\u6CD5\u628A\u4F7F\u7528\u533A\u6D3B\u7740\u7684\u5BF9\u8C61\u590D\u5236\u5230\u7A7A\u95F2\u533A\u5E76\u6392\u5E8F\uFF08<strong>\u89E3\u51B3\u5185\u5B58\u788E\u7247\u5316\u95EE\u9898</strong>\uFF09\uFF0C\u968F\u540E\u6E05\u7406\u4F7F\u7528\u533A\u5269\u4F59\u672A\u6807\u8BB0\u7684\u5783\u573E\uFF0C\u6B64\u65F6\u4F7F\u7528\u533A\u53D8\u6210\u7A7A\u95F2\u533A\uFF0C\u7A7A\u95F2\u533A\u53D8\u6210\u4F7F\u7528\u533A\u3002\u4E0A\u8FF0\u8FC7\u7A0B\u53CD\u590D\uFF0C\u4E00\u4E2A\u5BF9\u8C61\u591A\u6B21\u590D\u5236\u540E\u4ECD\u5B58\u6D3B\u5C31\u76F4\u63A5\u79FB\u5230<strong>\u8001\u751F\u4EE3\u533A</strong>\uFF0C\u5C31\u50CF\u4E24\u4E2A\u676F\u5B50\uFF0C\u4E00\u676F\u6C34\u5012\u6765\u5012\u53BB\uFF0C\u4E00\u76F4\u6CA1\u6492\u51FA\u53BB\u7684\u5C31\u662F\u5B58\u6D3B\u8F83\u4E45\u7684\uFF0C\u53EF\u4EE5\u79FB\u5230<strong>\u8001\u751F\u4EE3\u533A</strong>\u3002\u6216\u8005\u5F53\u5BF9\u8C61\u590D\u5236\u5230\u7A7A\u95F2\u533A\uFF0C\u5185\u5B58\u8D85\u8FC7\u7A7A\u95F2\u533A\u768425%\u65F6\uFF0C\u4E5F\u4F1A\u76F4\u63A5\u79FB\u5230\u8001\u751F\u4EE3\u533A\u3002</p><p><strong>\u8001\u751F\u4EE3\u533A</strong></p><p>\u200B \u8001\u751F\u4EE3\u533A\u4F7F\u7528<strong>\u6807\u8BB0\u6E05\u9664</strong>(<code>Mark-Sweep</code>)\uFF0C\u4ECE\u6839\u8282\u70B9(dom\u3001window\u3001global)\u904D\u5386\u6807\u8BB0\u6D3B\u7740\u7684\u5BF9\u8C61\uFF0C\u56DE\u6536\u5668\u5B9A\u65F6\u6E05\u7406\u6B7B\u4EA1\u7684\u5BF9\u8C61\u3002\u4F7F\u7528<strong>\u6807\u8BB0\u6574\u7406\u7B97\u6CD5</strong>\u628A\u6807\u8BB0\u7684\u5BF9\u8C61\u5411\u5185\u5B58\u4E00\u7AEF\u79FB\u52A8\uFF08<strong>\u89E3\u51B3\u6807\u8BB0\u6E05\u9664\u7684\u5185\u5B58\u788E\u7247\u5316\u95EE\u9898</strong>\uFF09</p><p>tip\uFF1A <code>Scavenge</code>\u53EA\u590D\u5236\u6D3B\u7740\u7684\u5BF9\u8C61\uFF0C<code>Mark-Sweep</code>\u53EA\u6E05\u9664\u6B7B\u4EA1\u7684\u5BF9\u8C61\u3002\u6D3B\u5BF9\u8C61\u5728\u65B0\u751F\u4EE3\u533A\u8F83\u5C11\uFF0C\u6B7B\u5BF9\u8C61\u5728\u8001\u751F\u4EE3\u4E2D\u4EA4\u5C11\uFF0C\u8FD9\u662F\u4E24\u79CD\u56DE\u6536\u65B9\u5F0F\u9AD8\u6548\u7684\u539F\u56E0\u3002</p><p><strong>\u5E76\u884C\u56DE\u6536</strong></p><p>\u200B js\u662F\u5355\u7EBF\u7A0B\uFF0C\u6240\u4EE5\u5783\u573E\u56DE\u6536\u4F1A\u963B\u585Ejs\u811A\u672C\u7684\u6267\u884C\uFF0C<strong>\u5E76\u884C\u56DE\u6536</strong>\u5C31\u662F\u5F00\u542F\u8F85\u52A9\u7EBF\u7A0B\u5E2E\u52A9\u5783\u573E\u56DE\u6536\u3002</p><p>\u200B \u7F3A\u70B9\uFF1A\u50CF\u8001\u751F\u4EE3\u533A\u6D3B\u7740\u7684\u5BF9\u8C61\u5927\u800C\u591A\uFF0C\u5C31\u7B97\u662F\u5E76\u884C\u4EFB\u52A1\uFF0C\u4E00\u6B21\u7684\u6E05\u7406\u4EFB\u52A1\u4E5F\u53EF\u80FD\u8FC7\u91CD\u5BFC\u81F4\u963B\u585E\u8FC7\u957F\uFF0C\u6240\u4EE5\u9700\u8981\u4F7F\u7528<strong>\u589E\u91CF\u6807\u8BB0</strong>\u548C<strong>\u60F0\u6027\u6E05\u7406</strong>\u3002</p><p><strong>\u589E\u91CF\u6807\u8BB0</strong></p><p>\u200B \u628A\u56DE\u6536\u4EFB\u52A1\u5206\u6210\u4E00\u5C0F\u6B65\u4E00\u5C0F\u6B65\u7684\uFF0C\u6267\u884C\u5B8C\u4E00\u5C0F\u6B65\u518D\u628A\u4E3B\u7EBF\u7A0B\u4EA4\u7ED9js\uFF0C\u8FD9\u6837\u4EA4\u66FF\u589E\u91CF\u6267\u884C\u5B8C\u4E00\u6B21\u6807\u8BB0\u4EFB\u52A1\uFF0C\u4F46\u53EF\u80FD\u4F1A\u51FA\u73B0\u6267\u884C\u4EFB\u52A1\u7A0B\u5E8F\u65F6\u5185\u5B58\u4E2D\u6807\u8BB0\u597D\u7684\u5BF9\u8C61\u5F15\u7528\u5173\u7CFB\u88AB\u4FEE\u6539\u7684\u95EE\u9898\uFF0C\u6240\u4EE5\u9700\u8981\u5F15\u5165<strong>\u4E09\u8272\u6807\u8BB0\u6CD5</strong>\u548C<strong>\u5199\u5C4F\u969C\u6CD5</strong>\u6765\u89E3\u51B3\u3002</p><p><strong>\u60F0\u6027\u6E05\u7406</strong></p><p>\u200B \u5728\u5185\u5B58\u5145\u8DB3\u60C5\u51B5\u5148\u4F18\u5148\u6267\u884Cjs\u4EE3\u7801\uFF0C\u4E3B\u7EBF\u7A0B\u7A7A\u95F2\u65F6\u624D\u6E05\u7406\u5783\u573E\uFF0C\u65E0\u9700\u4E00\u6B21\u53BB\u6E05\u7406\u5B8C\u672A\u6807\u8BB0\u7684\u5BF9\u8C61\uFF0C\u9010\u4E00\u6E05\u7406\uFF0C\u914D\u5408\u589E\u91CF\u6807\u8BB0\u4F7F\u7528</p><p>\u200B \u7F3A\u70B9\uFF1A\u589E\u91CF\u6807\u8BB0\u540E\u60F0\u6027\u6E05\u7406\uFF0C\u6CA1\u6709\u51CF\u5C11\u5360\u7528\u4E3B\u7EBF\u7A0B\u7684\u65F6\u95F4\uFF0C\u751A\u81F3\u589E\u52A0\u4E86\u3002</p><p><strong>\u5E76\u53D1\u56DE\u6536</strong></p><p>\u200B \u5B8C\u5168\u5728\u8F85\u52A9\u7EBF\u7A0B\u6267\u884C\uFF0C\u4E0D\u4F1A\u5360\u7528\u4E3B\u7EBF\u7A0B\u3002</p><p>\u200B \u7F3A\u70B9\uFF1A\u9700\u8981\u8003\u8651\u5783\u573E\u56DE\u6536\u5668\u5728\u8F85\u52A9\u7EBF\u7A0B\u5DF2\u7ECF\u505A\u7684\u6807\u8BB0\u6216\u8005\u6B63\u5728\u505A\u6807\u8BB0\u65F6\uFF0Cjs\u5BF9\u8C61\u5F15\u7528\u7684\u6539\u53D8\uFF0C\u9700\u8981\u989D\u5916\u5B9E\u73B0\u8BFB\u5199\u9501\u673A\u5236\u3002</p><p>v8\u5783\u573E\u56DE\u6536\u673A\u5236\u5C31\u662F\u6839\u636E\u4E0A\u8FF0\u65B9\u6CD5\u7684\u4F18\u7F3A\u70B9\uFF0C\u7ED3\u5408\u4F7F\u7528\u3002</p><p>\u53C2\u8003\uFF1A</p><p>1\u3001\u300A\u6DF1\u5165\u6D45\u51FAnodejs\u300B5.1- v8\u7684\u5783\u573E\u56DE\u6536\u673A\u5236\u4E0E\u5185\u5B58\u9650\u5236</p><p>2\u3001\u6398\u91D1\uFF1Ahttps://juejin.cn/post/6981588276356317214?share_token=6cecbce3-8f54-4e4a-9049-d73399fa76e8</p>',29);function n(p,e){return t}var a=s(r,[["render",n],["__file","v8\u5783\u573E\u56DE\u6536\u673A\u523620210825.html.vue"]]);export{a as default};
